(13591,423,'key_features','a:6:{i:0;a:2:{s:5:\"title\";s:19:\"Quick-Lock Assembly\";s:11:\"description\";s:131:\"10 seconds per cabinet installation with precision quick-lock connectors. Two people can set up a full stage wall in under 2 hours.\";}i:1;a:2:{s:5:\"title\";s:28:\"Lightweight Die-Cast Cabinet\";s:11:\"description\";s:121:\"Ultra-thin aluminum die-cast cabinet is easy to transport and stack. Reduces shipping costs and setup time significantly.\";}i:2;a:2:{s:5:\"title\";s:23:\"Indoor & Outdoor Models\";s:11:\"description\";s:116:\"Full range from P2.6 indoor to P4.8 outdoor rental. IP50 for indoor events, IP65 for outdoor festivals and concerts.\";}i:3;a:2:{s:5:\"title\";s:22:\"One Cabinet, Many Uses\";s:11:\"description\";s:118:\"Upgrade display quality by swapping modules only — no need to replace cabinets, reducing long-term investment costs.\";}i:4;a:2:{s:5:\"title\";s:23:\"Status Indicator Lights\";s:11:\"description\";s:113:\"Built-in LED indicators show power and signal status at a glance, simplifying fault identification during events.\";}i:5;a:2:{s:5:\"title\";s:27:\"Curved & Flat Configuration\";s:11:\"description\";s:112:\"Supports both flat and arc configurations. Create concave or convex curved displays for immersive stage designs.\";}}'),
