(14495,445,'key_features','a:6:{i:0;a:2:{s:5:\"title\";s:19:\"500KG Load Capacity\";s:11:\"description\";s:124:\"High-strength anti-slip wear-resistant surface cover. Walk-on rated with stainless steel exterior for outdoor installations.\";}i:1;a:2:{s:5:\"title\";s:22:\"IP65 Waterproof Rating\";s:11:\"description\";s:107:\"Fully waterproof for indoor and outdoor use. Can be cleaned with water hose outdoors or damp cloth indoors.\";}i:2;a:2:{s:5:\"title\";s:26:\"Interactive Sensor Support\";s:11:\"description\";s:122:\"Compatible with infrared and pressure sensors for real-time interactive effects. Ideal for experiential retail and events.\";}i:3;a:2:{s:5:\"title\";s:32:\"0-5000 nit Adjustable Brightness\";s:11:\"description\";s:110:\"Wide brightness range adapts to any lighting environment from dim nightclub floors to bright exhibition halls.\";}i:4;a:2:{s:5:\"title\";s:21:\"Anti-Shock Face Cover\";s:11:\"description\";s:108:\"Shock-absorbing plastic face cover resists scratches and impact. Easy to clean and maintain surface clarity.\";}i:5;a:2:{s:5:\"title\";s:25:\"Seamless Modular Assembly\";s:11:\"description\";s:107:\"Direct-lay or guided-rail installation. Cabinets connect seamlessly for flat, flush floor display surfaces.\";}}'),
