(18386,819,'key_features','a:6:{i:0;a:2:{s:5:\"title\";s:21:\"XR 虚拟制片优化\";s:11:\"description\";s:123:\"专为高帧率影视摄像与低延迟播控系统设计。无摩尔纹及画面跳动，符合虚拟拍摄行业规范。\";}i:1;a:2:{s:5:\"title\";s:21:\"广色域色彩表现\";s:11:\"description\";s:113:\"覆盖 DCI-P3 广色域，色彩深度高，支持广播级画面调色与渲染，让数字场景无比逼真。\";}i:2;a:2:{s:5:\"title\";s:18:\"多维几何构建\";s:11:\"description\";s:104:\"支持天幕屏、立面直/弧墙、地砖屏多折面无缝组装，打造沉浸式 3D 环幕空间。\";}i:3;a:2:{s:5:\"title\";s:21:\"像素级色彩校准\";s:11:\"description\";s:108:\"采用高精度相机逐点进行亮度及色度校准，确保演播室长期拼缝亮暗线完美消失。\";}i:4;a:2:{s:5:\"title\";s:21:\"高帧率芯片驱动\";s:11:\"description\";s:115:\"采用专业级高刷高帧率驱动 IC，支持 240Hz 以上画面流畅输出，配合高速相机平滑捕捉。\";}i:5;a:2:{s:5:\"title\";s:18:\"专业中控平台\";s:11:\"description\";s:113:\"完美适配 Brompton 或 Megapixel 旗舰播控卡，支持 HDR 高动态画面渲染与专业级分色调整。\";}}'),
