(21588,846,'_key_features_0_title','field_feat_title'),
(21589,846,'key_features_0_description','高达 288,900 像素/m²。近距离阅读文字时清晰锐利，能完美呈现高对比度视频广告。'),
(21590,846,'_key_features_0_description','field_feat_desc'),
(21591,846,'key_features_1_title','一体万向轮折叠支架'),
(21592,846,'_key_features_1_title','field_feat_title'),
(21593,846,'key_features_1_description','机身自带 360° 静音带锁万向轮和折叠式背置支架，单人即推即走、随停随放，免安装。'),
(21594,846,'_key_features_1_description','field_feat_desc'),
