(21596,846,'_key_features_2_title','field_feat_title'),
(21597,846,'key_features_2_description','支持跨省市、全球跨网络多屏同步发布排程，可通过手机 App/网页远程监控屏幕状态与亮度。'),
(21598,846,'_key_features_2_description','field_feat_desc'),
