(21600,846,'_key_features_3_title','field_feat_title'),
(21601,846,'key_features_3_description','无需拼接处理器，仅需普通 HDMI 线级联，即可实现 6 台海报屏拼接为一面标准 16:9 2K 视频墙。'),
(21602,846,'_key_features_3_description','field_feat_desc'),
