(21604,846,'_key_features_4_title','field_feat_title'),
(21605,846,'key_features_4_description','机身外框厚度仅为 60mm，采用黑色磨砂阳极氧化铝合金边框，实现正面全面屏显示视觉效果。'),
(21606,846,'_key_features_4_description','field_feat_desc'),
