(21635,425,'_wp_old_slug','rental-indoor-p3-9'),
(21636,425,'pixel_density','65,536 dots/m²'),
(21637,425,'cabinet_weight_kg','7.0 kg / 12.25 kg'),
(21638,425,'key_features_0_title','Lightweight Design - Slim Structure'),
(21639,425,'key_features_0_description','Thin and lightweight cabinet, convenient for assembly, disassembly, and transportation. The cabinet is made of die-cast aluminum with high strength, high toughness, high precision, and is not easy to deform, saving effort for transportation.'),
(21640,425,'key_features_1_title','Excellent Craftsmanship - Seamless Splicing'),
(21641,425,'key_features_1_description','The cabinet connection adopts a quick lock structure, allowing the installation of one cabinet to be completed in 10 seconds. Seamless splicing ensures smooth playback and vibrant colors.'),
(21642,425,'key_features_2_title','Delicate Image Processing - Low Brightness & High Grayscale'),
(21643,425,'key_features_2_description','High-quality black-face LED lamps are used, matching with black masks for higher contrast, making the picture clearer and more vivid.'),
(21650,428,'_wp_old_slug','rental-outdoor-p3-9'),
(21651,428,'pixel_density','65,536 dots/m²'),
(21652,428,'cabinet_weight_kg','7.0 kg / 12.25 kg'),
(21653,428,'key_features_0_title','IP65 Rated Die-cast Cabinet'),
(21654,428,'key_features_0_description','High-strength die-cast aluminum structure weighs only 7.5kg, offering IP65 waterproof dustproof protection and extreme mechanical strength.'),
(21655,428,'key_features_1_title','Sunlight Readable ≥4500 nit'),
(21656,428,'key_features_1_description','Delivers high brightness and contrast, ensuring perfect visual readability and color saturation under direct sunlight.'),
(21657,428,'key_features_2_title','Reinforced Quick Locks'),
(21658,428,'key_features_2_description','Industrial quick-release locks provide superior pull load limits, maintaining seamless connections even under heavy wind loads.'),
(21659,428,'key_features_3_title','Ultra-High Refresh Rate'),
(21660,428,'key_features_3_description','≥3840Hz refresh rate combined with 14-bit grayscale ensures flicker-free and seamless visual broadcast under camera lenses.'),
(21661,428,'key_features_4_title','Built-in Folding Corner Guards'),
(21662,428,'key_features_4_description','Fold-out metal corner guards lift the bottom LEDs off the ground, preventing collision damage during transport and staging.'),
(21663,428,'key_features_5_title','Dual-Access Service'),
(21664,428,'key_features_5_description','Magnetic modules support front-access servicing while power control box supports rear plug-and-play hot-swapping in 10 seconds.'),
(21665,783,'_wp_old_slug','rental-indoor-p3-9-zh'),
(21666,783,'pixel_density','65536'),
(21667,783,'cabinet_weight_kg','7 / 12.25 kg'),
(21668,783,'_product_gallery','field_prod_gallery'),
(21669,783,'key_features_0_title','轻量化设计-结构轻薄'),
(21670,783,'key_features_0_description','箱体轻薄，方便装拆和运输，箱体釆用压铸铝成型，强度高、韧性强、精度高、不易变形，为运输省力。'),
(21671,783,'key_features_1_title','卓越的工艺-无缝拼接'),
(21672,783,'key_features_1_description','箱体连接采用快速锁扣结构，10秒即可完成一个箱体的安装，无缝拼接，播放画面流畅，颜色鲜艳。'),
(21673,783,'key_features_2_title','画面处理细腻-低亮高灰'),
(21674,783,'key_features_2_description','采用高品质黑面LED灯,配合黑色面罩、对比度更高使画面更加清晰和鲜艳。'),
(21681,786,'_wp_old_slug','rental-outdoor-p3-9-zh'),
(21682,786,'pixel_density','65536'),
(21683,786,'cabinet_weight_kg','7 / 12.25 kg'),
(21684,786,'_product_gallery','field_prod_gallery'),
(21685,786,'key_features_0_title','轻量化户外防水压铸铝箱体'),
(21686,786,'key_features_0_description','高强度压铸铝一体成型箱体，尺寸 500×500 mm，单箱重 7.5 kg。整箱达到前/后 IP65 高等级防尘防水，有效抵御暴雨。'),
(21687,786,'key_features_1_title','≥4500 nit 户外强光高亮'),
(21688,786,'key_features_1_description','白平衡亮度可达 ≥4500 nit，在烈日强光直射下画面依然清晰艳丽、色彩饱和度高，带来完美的户外视觉体验。'),
(21689,786,'key_features_2_title','工业防风增强侧锁'),
(21690,786,'key_features_2_description','快速锁设计具备更大拉力负荷，有效应对户外现场风吹晃动，防止拼接拉伸产生裂缝，拼装严丝合缝。'),
(21691,786,'key_features_3_title','超高刷新率'),
(21692,786,'key_features_3_description','≥3840Hz 刷新率结合 14 位灰度处理技术，在手机和高清广播摄像机镜头下保持高清纯净画质。'),
(21693,786,'key_features_4_title','快速防撞转角保护'),
(21694,786,'key_features_4_description','转角外侧设计可翻折式护角，落地推移时彻底托起下缘模组，保障转弯等碰撞安全，保护灯珠。'),
(21695,786,'key_features_5_title','前/后极速维护'),
(21696,786,'key_features_5_description','支持挂墙吊装从前面板吸取模组，也支持后台从后背板开箱检修，双通道提高维护时效，现场拆装免工具。'),
